@using sv_67f96d5a1beb4803827c2b39e6df992f.Models

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.FullName" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(emailInvalid ? "is-invalid" : "")"
               @bind="Model.Email" @bind:event="oninput" />
        @if (emailInvalid)
        {
            <div class="invalid-feedback">Please enter a valid email address.</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.Address" @bind:event="oninput" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
        @if (isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? errorMessage;
    private bool emailInvalid;
    private bool isValidating;

    private async Task HandleNext()
    {
        errorMessage = null;
        emailInvalid = false;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            errorMessage = "All fields are required.";
            return;
        }

        if (ValidateEmail is not null)
        {
            isValidating = true;
            StateHasChanged();
            try
            {
                var isValid = await ValidateEmail(Model.Email);
                if (!isValid)
                {
                    emailInvalid = true;
                    errorMessage = "The email address could not be validated.";
                    return;
                }
            }
            finally
            {
                isValidating = false;
            }
        }

        await OnNext.InvokeAsync();
    }
}

